package cli

import (
	"context"
	"crypto/sha256"
	_ "embed"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"log/slog"
	"os"
	"os/exec"
	"path/filepath"
	"sort"
	"strings"
	"time"

	"github.com/entireio/cli/cmd/entire/cli/logging"
	"github.com/entireio/cli/cmd/entire/cli/paths"
	"github.com/entireio/cli/cmd/entire/cli/settings"
	"github.com/entireio/cli/cmd/entire/cli/strategy"
	"github.com/spf13/cobra"
)

// WingmanPayload is the data passed to the detached review subprocess.
type WingmanPayload struct {
	SessionID     string   `json:"session_id"`
	RepoRoot      string   `json:"repo_root"`
	BaseCommit    string   `json:"base_commit"`
	ModifiedFiles []string `json:"modified_files"`
	NewFiles      []string `json:"new_files"`
	DeletedFiles  []string `json:"deleted_files"`
	Prompts       []string `json:"prompts"`
	CommitMessage string   `json:"commit_message"`
}

// WingmanState tracks deduplication and review state.
type WingmanState struct {
	SessionID        string     `json:"session_id"`
	FilesHash        string     `json:"files_hash"`
	ReviewedAt       time.Time  `json:"reviewed_at"`
	ReviewApplied    bool       `json:"review_applied"`
	ApplyAttemptedAt *time.Time `json:"apply_attempted_at,omitempty"`
}

//go:embed wingman_instruction.md
var wingmanApplyInstruction string

const (
	wingmanStateFile  = ".entire/wingman-state.json"
	wingmanReviewFile = ".entire/REVIEW.md"
	wingmanLockFile   = ".entire/wingman.lock"

	// wingmanStaleReviewTTL is the maximum age of a pending REVIEW.md before
	// it's considered stale and automatically cleaned up.
	wingmanStaleReviewTTL = 1 * time.Hour
)

func newWingmanCmd() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "wingman",
		Short: "Automated code review for agent sessions",
		Long: `Wingman provides automated code review after agent turns.

When enabled, wingman automatically reviews code changes made by agents,
writes suggestions to .entire/REVIEW.md, and optionally triggers the agent
to apply them.`,
		RunE: func(cmd *cobra.Command, _ []string) error {
			return cmd.Help()
		},
	}

	cmd.AddCommand(newWingmanEnableCmd())
	cmd.AddCommand(newWingmanDisableCmd())
	cmd.AddCommand(newWingmanStatusCmd())
	cmd.AddCommand(newWingmanReviewCmd())
	cmd.AddCommand(newWingmanApplyCmd())

	return cmd
}

func newWingmanEnableCmd() *cobra.Command {
	var useLocal bool

	cmd := &cobra.Command{
		Use:   "enable",
		Short: "Enable wingman auto-review",
		RunE: func(cmd *cobra.Command, _ []string) error {
			if _, err := paths.RepoRoot(); err != nil {
				fmt.Fprintln(cmd.ErrOrStderr(), "Not a git repository. Please run from within a git repository.")
				return NewSilentError(errors.New("not a git repository"))
			}

			// Load merged settings to check preconditions
			merged, err := settings.Load()
			if err != nil {
				return fmt.Errorf("failed to load settings: %w", err)
			}

			if !merged.Enabled {
				fmt.Fprintln(cmd.ErrOrStderr(), "Entire is not enabled. Run 'entire enable' first.")
				return NewSilentError(errors.New("entire not enabled"))
			}

			// Load the target file specifically so we don't bloat it with merged values
			s, err := loadSettingsTarget(useLocal)
			if err != nil {
				return fmt.Errorf("failed to load settings: %w", err)
			}

			if s.StrategyOptions == nil {
				s.StrategyOptions = make(map[string]any)
			}
			s.StrategyOptions["wingman"] = map[string]any{"enabled": true}

			if err := saveSettingsTarget(s, useLocal); err != nil {
				return fmt.Errorf("failed to save settings: %w", err)
			}

			msg := "Wingman enabled. Code changes will be automatically reviewed after agent turns."
			if useLocal {
				msg += " (saved to settings.local.json)"
			}
			fmt.Fprintln(cmd.OutOrStdout(), msg)
			return nil
		},
	}

	cmd.Flags().BoolVar(&useLocal, "local", false, "Write to settings.local.json instead of settings.json")

	return cmd
}

func newWingmanDisableCmd() *cobra.Command {
	var useLocal bool

	cmd := &cobra.Command{
		Use:   "disable",
		Short: "Disable wingman auto-review",
		RunE: func(cmd *cobra.Command, _ []string) error {
			s, err := loadSettingsTarget(useLocal)
			if err != nil {
				return fmt.Errorf("failed to load settings: %w", err)
			}

			if s.StrategyOptions == nil {
				s.StrategyOptions = make(map[string]any)
			}
			s.StrategyOptions["wingman"] = map[string]any{"enabled": false}

			if err := saveSettingsTarget(s, useLocal); err != nil {
				return fmt.Errorf("failed to save settings: %w", err)
			}

			// Clean up pending review file if it exists
			reviewPath, err := paths.AbsPath(wingmanReviewFile)
			if err == nil {
				_ = os.Remove(reviewPath)
			}

			msg := "Wingman disabled."
			if useLocal {
				msg += " (saved to settings.local.json)"
			}
			fmt.Fprintln(cmd.OutOrStdout(), msg)
			return nil
		},
	}

	cmd.Flags().BoolVar(&useLocal, "local", false, "Write to settings.local.json instead of settings.json")

	return cmd
}

// loadSettingsTarget loads settings from the appropriate file based on the --local flag.
// When local is true, loads from settings.local.json only (without merging).
// When local is false, loads the merged settings (project + local).
func loadSettingsTarget(local bool) (*settings.EntireSettings, error) {
	if !local {
		s, err := settings.Load()
		if err != nil {
			return nil, fmt.Errorf("loading settings: %w", err)
		}
		return s, nil
	}
	absPath, err := paths.AbsPath(settings.EntireSettingsLocalFile)
	if err != nil {
		absPath = settings.EntireSettingsLocalFile
	}
	s, err := settings.LoadFromFile(absPath)
	if err != nil {
		return nil, fmt.Errorf("loading local settings: %w", err)
	}
	return s, nil
}

// saveSettingsTarget saves settings to the appropriate file based on the --local flag.
func saveSettingsTarget(s *settings.EntireSettings, local bool) error {
	if local {
		if err := settings.SaveLocal(s); err != nil {
			return fmt.Errorf("saving local settings: %w", err)
		}
		return nil
	}
	if err := settings.Save(s); err != nil {
		return fmt.Errorf("saving settings: %w", err)
	}
	return nil
}

func newWingmanStatusCmd() *cobra.Command {
	return &cobra.Command{
		Use:   "status",
		Short: "Show wingman status",
		RunE: func(cmd *cobra.Command, _ []string) error {
			s, err := settings.Load()
			if err != nil {
				return fmt.Errorf("failed to load settings: %w", err)
			}

			if s.IsWingmanEnabled() {
				fmt.Fprintln(cmd.OutOrStdout(), "Wingman: enabled")
			} else {
				fmt.Fprintln(cmd.OutOrStdout(), "Wingman: disabled")
			}

			// Show last review info if available
			state, err := loadWingmanState()
			if err == nil && state != nil {
				fmt.Fprintf(cmd.OutOrStdout(), "Last review: %s\n", state.ReviewedAt.Format(time.RFC3339))
				if state.ReviewApplied {
					fmt.Fprintln(cmd.OutOrStdout(), "Status: applied")
				} else {
					fmt.Fprintln(cmd.OutOrStdout(), "Status: pending")
				}
			}

			// Check for pending REVIEW.md
			reviewPath, err := paths.AbsPath(wingmanReviewFile)
			if err == nil {
				if _, statErr := os.Stat(reviewPath); statErr == nil {
					fmt.Fprintln(cmd.OutOrStdout(), "Pending review: .entire/REVIEW.md")
				}
			}

			return nil
		},
	}
}

// triggerWingmanReview checks preconditions and spawns the detached review process.
func triggerWingmanReview(payload WingmanPayload) {
	// Prevent infinite recursion: if we're inside a wingman auto-apply,
	// don't trigger another review. The env var is set by triggerAutoApply.
	if os.Getenv("ENTIRE_WINGMAN_APPLY") != "" {
		return
	}

	logCtx := logging.WithComponent(context.Background(), "wingman")
	repoRoot := payload.RepoRoot

	totalFiles := len(payload.ModifiedFiles) + len(payload.NewFiles) + len(payload.DeletedFiles)
	logging.Info(logCtx, "wingman trigger evaluating",
		slog.String("session_id", payload.SessionID),
		slog.Int("file_count", totalFiles),
	)

	// Check if a pending REVIEW.md already exists for the current session
	if shouldSkipPendingReview(repoRoot, payload.SessionID) {
		logging.Info(logCtx, "wingman skipped: pending review exists for current session")
		fmt.Fprintf(os.Stderr, "[wingman] Pending review exists, skipping\n")
		return
	}

	// Atomic lock file prevents concurrent review spawns. O_CREATE|O_EXCL
	// is atomic on all platforms, avoiding the TOCTOU race of Stat+WriteFile.
	lockPath := filepath.Join(repoRoot, wingmanLockFile)
	if !acquireWingmanLock(lockPath, payload.SessionID) {
		logging.Info(logCtx, "wingman skipped: review already in progress")
		fmt.Fprintf(os.Stderr, "[wingman] Review in progress, skipping\n")
		return
	}

	// Dedup check: compute hash of sorted file paths
	allFiles := make([]string, 0, len(payload.ModifiedFiles)+len(payload.NewFiles)+len(payload.DeletedFiles))
	allFiles = append(allFiles, payload.ModifiedFiles...)
	allFiles = append(allFiles, payload.NewFiles...)
	allFiles = append(allFiles, payload.DeletedFiles...)
	filesHash := computeFilesHash(allFiles)

	state, _ := loadWingmanState() //nolint:errcheck // best-effort dedup
	if state != nil && state.FilesHash == filesHash && state.SessionID == payload.SessionID {
		logging.Info(logCtx, "wingman skipped: dedup hash match",
			slog.String("files_hash", filesHash[:12]),
		)
		fmt.Fprintf(os.Stderr, "[wingman] Already reviewed these changes, skipping\n")
		return
	}

	// Capture HEAD at trigger time so the detached review diffs against
	// the correct commit even if HEAD moves during the initial delay.
	payload.BaseCommit = resolveHEAD(repoRoot)
	logging.Debug(logCtx, "wingman captured base commit",
		slog.String("base_commit", payload.BaseCommit),
	)

	// Write payload to a temp file instead of passing as a CLI argument,
	// which can exceed OS argv limits (~128KB Linux, ~256KB macOS) with
	// many files or long prompts.
	payloadJSON, err := json.Marshal(payload)
	if err != nil {
		logging.Error(logCtx, "wingman failed to marshal payload", slog.Any("error", err))
		fmt.Fprintf(os.Stderr, "[wingman] Failed to marshal payload: %v\n", err)
		_ = os.Remove(lockPath)
		return
	}
	payloadPath := filepath.Join(repoRoot, ".entire", "wingman-payload.json")
	//nolint:gosec // G306: payload file is not secrets
	if err := os.WriteFile(payloadPath, payloadJSON, 0o644); err != nil {
		logging.Error(logCtx, "wingman failed to write payload file", slog.Any("error", err))
		fmt.Fprintf(os.Stderr, "[wingman] Failed to write payload file: %v\n", err)
		_ = os.Remove(lockPath)
		return
	}

	// Spawn detached review process with path to payload file
	spawnDetachedWingmanReview(repoRoot, payloadPath)
	logging.Info(logCtx, "wingman review spawned",
		slog.String("session_id", payload.SessionID),
		slog.String("base_commit", payload.BaseCommit),
		slog.Int("file_count", totalFiles),
	)
	fmt.Fprintf(os.Stderr, "[wingman] Review starting in background...\n")
}

// triggerWingmanFromCommit builds a wingman payload from the HEAD commit and
// triggers a review. Used by the git post-commit hook for manual-commit strategy
// where files are committed by the user (not by SaveChanges).
func triggerWingmanFromCommit() {
	// Prevent infinite recursion: skip if inside wingman auto-apply
	if os.Getenv("ENTIRE_WINGMAN_APPLY") != "" {
		return
	}
	if !settings.IsWingmanEnabled() {
		return
	}

	repoRoot, err := paths.RepoRoot()
	if err != nil {
		return
	}

	head := resolveHEAD(repoRoot)
	if head == "" {
		return
	}

	// Get changed files from the commit
	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()
	//nolint:gosec // G204: head is from git rev-parse, not user input
	cmd := exec.CommandContext(ctx, "git", "diff-tree", "--no-commit-id", "--name-status", "-r", head)
	cmd.Dir = repoRoot
	out, err := cmd.Output()
	if err != nil || len(out) == 0 {
		return
	}

	var modified, newFiles, deleted []string
	for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
		if len(line) < 3 {
			continue
		}
		status := line[0]
		file := strings.TrimSpace(line[1:])
		switch status {
		case 'M':
			modified = append(modified, file)
		case 'A':
			newFiles = append(newFiles, file)
		case 'D':
			deleted = append(deleted, file)
		}
	}

	if len(modified)+len(newFiles)+len(deleted) == 0 {
		return
	}

	// Get commit message
	//nolint:gosec // G204: head is from git rev-parse, not user input
	msgCmd := exec.CommandContext(ctx, "git", "log", "-1", "--format=%B", head)
	msgCmd.Dir = repoRoot
	msgOut, _ := msgCmd.Output() //nolint:errcheck // best-effort commit message
	commitMessage := strings.TrimSpace(string(msgOut))

	sessionID := strategy.FindMostRecentSession()

	triggerWingmanReview(WingmanPayload{
		SessionID:     sessionID,
		RepoRoot:      repoRoot,
		ModifiedFiles: modified,
		NewFiles:      newFiles,
		DeletedFiles:  deleted,
		CommitMessage: commitMessage,
	})
}

// staleLockThreshold is how old a lock file can be before we consider it stale
// (e.g., the detached process was SIGKILLed and the defer never ran).
const staleLockThreshold = 30 * time.Minute

// acquireWingmanLock atomically creates the lock file. Returns true if acquired.
// If the lock already exists but is older than staleLockThreshold, it is removed
// and re-acquired (handles crashed detached processes).
func acquireWingmanLock(lockPath, sessionID string) bool {
	//nolint:gosec // G304: lockPath is constructed from repoRoot + constant
	f, err := os.OpenFile(lockPath, os.O_WRONLY|os.O_CREATE|os.O_EXCL, 0o644)
	if err != nil {
		if !errors.Is(err, os.ErrExist) {
			fmt.Fprintf(os.Stderr, "[wingman] Failed to create lock: %v\n", err)
			return false
		}
		// Lock exists — check if it's stale
		info, statErr := os.Stat(lockPath)
		if statErr != nil || time.Since(info.ModTime()) <= staleLockThreshold {
			fmt.Fprintf(os.Stderr, "[wingman] Review already in progress, skipping\n")
			return false
		}
		fmt.Fprintf(os.Stderr, "[wingman] Removing stale lock (age: %s)\n",
			time.Since(info.ModTime()).Round(time.Second))
		_ = os.Remove(lockPath)
		// Retry the atomic create
		//nolint:gosec // G304: lockPath is constructed from repoRoot + constant
		f, err = os.OpenFile(lockPath, os.O_WRONLY|os.O_CREATE|os.O_EXCL, 0o644)
		if err != nil {
			fmt.Fprintf(os.Stderr, "[wingman] Failed to create lock after stale removal: %v\n", err)
			return false
		}
	}
	_, _ = f.WriteString(sessionID) //nolint:errcheck // best-effort session ID write
	_ = f.Close()
	return true
}

// resolveHEAD returns the current HEAD commit hash, or empty string on error.
func resolveHEAD(repoRoot string) string {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	cmd := exec.CommandContext(ctx, "git", "rev-parse", "HEAD")
	cmd.Dir = repoRoot
	out, err := cmd.Output()
	if err != nil {
		return ""
	}
	return strings.TrimSpace(string(out))
}

// computeFilesHash returns a SHA256 hex digest of the sorted file paths.
// Uses null byte separator (impossible in filenames) to avoid ambiguity.
func computeFilesHash(files []string) string {
	sorted := make([]string, len(files))
	copy(sorted, files)
	sort.Strings(sorted)
	h := sha256.Sum256([]byte(strings.Join(sorted, "\x00")))
	return hex.EncodeToString(h[:])
}

// loadWingmanState loads the wingman state from .entire/wingman-state.json.
func loadWingmanState() (*WingmanState, error) {
	statePath, err := paths.AbsPath(wingmanStateFile)
	if err != nil {
		return nil, fmt.Errorf("resolving wingman state path: %w", err)
	}

	data, err := os.ReadFile(statePath) //nolint:gosec // path is repo-relative
	if err != nil {
		return nil, fmt.Errorf("reading wingman state: %w", err)
	}

	var state WingmanState
	if err := json.Unmarshal(data, &state); err != nil {
		return nil, fmt.Errorf("parsing wingman state: %w", err)
	}
	return &state, nil
}

// saveWingmanState saves the wingman state to .entire/wingman-state.json.
func saveWingmanState(state *WingmanState) error {
	statePath, err := paths.AbsPath(wingmanStateFile)
	if err != nil {
		return fmt.Errorf("resolving wingman state path: %w", err)
	}

	dir := filepath.Dir(statePath)
	if err := os.MkdirAll(dir, 0o750); err != nil {
		return fmt.Errorf("creating wingman state directory: %w", err)
	}

	data, err := json.MarshalIndent(state, "", "  ")
	if err != nil {
		return fmt.Errorf("marshaling wingman state: %w", err)
	}

	//nolint:gosec // G306: state file is config, not secrets
	if err := os.WriteFile(statePath, data, 0o644); err != nil {
		return fmt.Errorf("writing wingman state: %w", err)
	}
	return nil
}

// loadWingmanStateDirect reads the wingman state file directly from a known
// path under repoRoot. Returns nil if the file doesn't exist or can't be parsed.
func loadWingmanStateDirect(repoRoot string) *WingmanState {
	statePath := filepath.Join(repoRoot, wingmanStateFile)
	data, err := os.ReadFile(statePath) //nolint:gosec // path is repo-relative constant
	if err != nil {
		return nil
	}
	var state WingmanState
	if err := json.Unmarshal(data, &state); err != nil {
		return nil
	}
	return &state
}

// newWingmanApplyCmd returns a hidden subcommand used by the stop hook to
// apply a pending REVIEW.md via claude --continue in a detached subprocess.
func newWingmanApplyCmd() *cobra.Command {
	return &cobra.Command{
		Use:    "__apply",
		Hidden: true,
		Args:   cobra.ExactArgs(1),
		RunE: func(_ *cobra.Command, args []string) error {
			return runWingmanApply(args[0])
		},
	}
}

// shouldSkipPendingReview checks whether a pending REVIEW.md should prevent
// a new review from being triggered. It cleans up stale/orphaned reviews.
//
// Returns true only when REVIEW.md exists AND belongs to the current session
// AND is younger than wingmanStaleReviewTTL.
func shouldSkipPendingReview(repoRoot, currentSessionID string) bool {
	reviewPath := filepath.Join(repoRoot, wingmanReviewFile)
	if _, err := os.Stat(reviewPath); err != nil {
		return false // No REVIEW.md, don't skip
	}

	// REVIEW.md exists — check state to determine if it's current or stale
	state := loadWingmanStateDirect(repoRoot)
	if state == nil {
		// Orphan: REVIEW.md without state file — clean up
		_ = os.Remove(reviewPath)
		return false
	}

	if state.SessionID != currentSessionID {
		// Different session — stale review, clean up
		_ = os.Remove(reviewPath)
		return false
	}

	if time.Since(state.ReviewedAt) > wingmanStaleReviewTTL {
		// Same session but too old — clean up
		_ = os.Remove(reviewPath)
		return false
	}

	return true // Current session, fresh review — skip
}

package cli

import (
	"bytes"
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"time"

	"github.com/entireio/cli/cmd/entire/cli/session"
	"github.com/spf13/cobra"
)

// wingmanLog writes a timestamped log line to stderr. In the detached subprocess,
// stderr is redirected to .entire/logs/wingman.log by the spawner.
func wingmanLog(format string, args ...any) {
	msg := fmt.Sprintf(format, args...)
	fmt.Fprintf(os.Stderr, "%s [wingman] %s\n", time.Now().Format(time.RFC3339), msg)
}

const (
	// wingmanInitialDelay is how long to wait before starting the review,
	// letting the agent turn fully settle.
	wingmanInitialDelay = 10 * time.Second

	// wingmanReviewModel is the Claude model used for reviews.
	wingmanReviewModel = "sonnet"

	// wingmanGitTimeout is the timeout for git diff operations.
	wingmanGitTimeout = 60 * time.Second

	// wingmanReviewTimeout is the timeout for the claude --print review call.
	wingmanReviewTimeout = 5 * time.Minute

	// wingmanApplyTimeout is the timeout for the claude --continue auto-apply call.
	wingmanApplyTimeout = 15 * time.Minute
)

// wingmanCLIResponse represents the JSON response from the Claude CLI --output-format json.
type wingmanCLIResponse struct {
	Result string `json:"result"`
}

func newWingmanReviewCmd() *cobra.Command {
	return &cobra.Command{
		Use:    "__review",
		Hidden: true,
		Args:   cobra.ExactArgs(1),
		RunE: func(_ *cobra.Command, args []string) error {
			return runWingmanReview(args[0])
		},
	}
}

func runWingmanReview(payloadPath string) error {
	wingmanLog("review process started (pid=%d)", os.Getpid())
	wingmanLog("reading payload from %s", payloadPath)

	// Read payload from file (avoids OS argv limits with large payloads)
	payloadJSON, err := os.ReadFile(payloadPath) //nolint:gosec // path is from our own spawn
	if err != nil {
		wingmanLog("ERROR reading payload: %v", err)
		return fmt.Errorf("failed to read payload file: %w", err)
	}
	// Clean up payload file after reading
	_ = os.Remove(payloadPath)

	var payload WingmanPayload
	if err := json.Unmarshal(payloadJSON, &payload); err != nil {
		wingmanLog("ERROR unmarshaling payload: %v", err)
		return fmt.Errorf("failed to unmarshal payload: %w", err)
	}

	repoRoot := payload.RepoRoot
	if repoRoot == "" {
		wingmanLog("ERROR repo_root is empty in payload")
		return errors.New("repo_root is required in payload")
	}

	totalFiles := len(payload.ModifiedFiles) + len(payload.NewFiles) + len(payload.DeletedFiles)
	wingmanLog("session=%s repo=%s base_commit=%s files=%d",
		payload.SessionID, repoRoot, payload.BaseCommit, totalFiles)

	// Clean up lock file when review completes (regardless of success/failure)
	lockPath := filepath.Join(repoRoot, wingmanLockFile)
	defer func() {
		if err := os.Remove(lockPath); err != nil && !errors.Is(err, os.ErrNotExist) {
			wingmanLog("WARNING: failed to remove lock file: %v", err)
		} else {
			wingmanLog("lock file removed")
		}
	}()

	// Initial delay: let the agent turn fully settle
	wingmanLog("waiting %s for agent turn to settle", wingmanInitialDelay)
	time.Sleep(wingmanInitialDelay)

	// Compute diff using the base commit captured at trigger time
	wingmanLog("computing diff (merge-base with main/master)")
	diffStart := time.Now()
	diff, err := computeDiff(repoRoot)
	if err != nil {
		wingmanLog("ERROR computing diff: %v", err)
		return fmt.Errorf("failed to compute diff: %w", err)
	}

	if strings.TrimSpace(diff) == "" {
		wingmanLog("no changes found in diff, exiting")
		return nil // No changes to review
	}
	wingmanLog("diff computed: %d bytes in %s", len(diff), time.Since(diffStart).Round(time.Millisecond))

	// Build file list for the prompt
	allFiles := make([]string, 0, len(payload.ModifiedFiles)+len(payload.NewFiles)+len(payload.DeletedFiles))
	for _, f := range payload.ModifiedFiles {
		allFiles = append(allFiles, f+" (modified)")
	}
	for _, f := range payload.NewFiles {
		allFiles = append(allFiles, f+" (new)")
	}
	for _, f := range payload.DeletedFiles {
		allFiles = append(allFiles, f+" (deleted)")
	}
	fileList := strings.Join(allFiles, ", ")

	// Read session context from checkpoint data (best-effort)
	sessionContext := readSessionContext(repoRoot, payload.SessionID)
	if sessionContext != "" {
		wingmanLog("session context loaded: %d bytes", len(sessionContext))
	}

	// Build review prompt
	prompt := buildReviewPrompt(payload.Prompts, payload.CommitMessage, sessionContext, payload.SessionID, fileList, diff)
	wingmanLog("review prompt built: %d bytes", len(prompt))

	// Call Claude CLI for review
	wingmanLog("calling claude CLI (model=%s, timeout=%s)", wingmanReviewModel, wingmanReviewTimeout)
	reviewStart := time.Now()
	reviewText, err := callClaudeForReview(repoRoot, prompt)
	if err != nil {
		wingmanLog("ERROR claude CLI failed after %s: %v", time.Since(reviewStart).Round(time.Millisecond), err)
		return fmt.Errorf("failed to get review from Claude: %w", err)
	}
	wingmanLog("review received: %d bytes in %s", len(reviewText), time.Since(reviewStart).Round(time.Millisecond))

	// Write REVIEW.md
	reviewPath := filepath.Join(repoRoot, wingmanReviewFile)
	if err := os.MkdirAll(filepath.Dir(reviewPath), 0o750); err != nil {
		wingmanLog("ERROR creating directory: %v", err)
		return fmt.Errorf("failed to create directory: %w", err)
	}
	//nolint:gosec // G306: review file is not secrets
	if err := os.WriteFile(reviewPath, []byte(reviewText), 0o644); err != nil {
		wingmanLog("ERROR writing REVIEW.md: %v", err)
		return fmt.Errorf("failed to write REVIEW.md: %w", err)
	}
	wingmanLog("REVIEW.md written to %s", reviewPath)

	// Update dedup state — write directly to known path instead of using
	// os.Chdir (which mutates process-wide state).
	allFilePaths := make([]string, 0, len(payload.ModifiedFiles)+len(payload.NewFiles)+len(payload.DeletedFiles))
	allFilePaths = append(allFilePaths, payload.ModifiedFiles...)
	allFilePaths = append(allFilePaths, payload.NewFiles...)
	allFilePaths = append(allFilePaths, payload.DeletedFiles...)

	saveWingmanStateDirect(repoRoot, &WingmanState{
		SessionID:     payload.SessionID,
		FilesHash:     computeFilesHash(allFilePaths),
		ReviewedAt:    time.Now(),
		ReviewApplied: false,
	})
	wingmanLog("dedup state saved")

	// If any session is live (IDLE/ACTIVE/ACTIVE_COMMITTED), don't auto-apply
	// in the background. The prompt-submit hook will inject REVIEW.md as
	// additionalContext when the user sends their next prompt — this is VISIBLE
	// in their terminal. Only use background auto-apply when no sessions are
	// alive (e.g., user closed all sessions).
	if hasAnyLiveSession(repoRoot) {
		wingmanLog("live session detected, deferring to prompt-submit injection (visible)")
		return nil
	}

	// No live sessions — apply in background as fallback
	wingmanLog("no live sessions, triggering background auto-apply")
	now := time.Now()
	state := loadWingmanStateDirect(repoRoot)
	if state != nil {
		state.ApplyAttemptedAt = &now
		saveWingmanStateDirect(repoRoot, state)
	}

	applyStart := time.Now()
	if err := triggerAutoApply(repoRoot); err != nil {
		wingmanLog("ERROR auto-apply failed after %s: %v", time.Since(applyStart).Round(time.Millisecond), err)
		return fmt.Errorf("failed to trigger auto-apply: %w", err)
	}
	wingmanLog("auto-apply completed in %s", time.Since(applyStart).Round(time.Millisecond))

	return nil
}

// computeDiff gets the full branch diff for review. It diffs the current HEAD
// against the merge base with the default branch (main/master), giving the
// reviewer a holistic view of all branch changes rather than just one commit.
func computeDiff(repoRoot string) (string, error) {
	ctx, cancel := context.WithTimeout(context.Background(), wingmanGitTimeout)
	defer cancel()

	// Find the merge base with the default branch for a holistic branch diff.
	mergeBase := findMergeBase(ctx, repoRoot)
	if mergeBase != "" {
		wingmanLog("using merge-base %s for branch diff", mergeBase)
		diff, err := gitDiff(ctx, repoRoot, mergeBase)
		if err == nil && strings.TrimSpace(diff) != "" {
			return diff, nil
		}
		// Fall through to HEAD diff if merge-base diff fails or is empty
	}

	// Fallback: diff uncommitted changes against HEAD
	wingmanLog("falling back to HEAD diff")
	diff, err := gitDiff(ctx, repoRoot, "HEAD")
	if err != nil {
		return "", fmt.Errorf("git diff failed: %w", err)
	}

	// If no uncommitted changes, try the latest commit itself
	if strings.TrimSpace(diff) == "" {
		diff, err = gitDiff(ctx, repoRoot, "HEAD~1", "HEAD")
		if err != nil {
			return "", fmt.Errorf("git diff for latest commit failed: %w", err)
		}
	}

	return diff, nil
}

// findMergeBase returns the merge-base commit between HEAD and the default
// branch (tries main, then master). Returns empty string if not found.
func findMergeBase(ctx context.Context, repoRoot string) string {
	for _, branch := range []string{"main", "master"} {
		cmd := exec.CommandContext(ctx, "git", "merge-base", branch, "HEAD") //nolint:gosec // branch is from hardcoded slice
		cmd.Dir = repoRoot
		out, err := cmd.Output()
		if err == nil {
			return strings.TrimSpace(string(out))
		}
	}
	return ""
}

// gitDiff runs git diff with the given args and returns stdout.
func gitDiff(ctx context.Context, repoRoot string, args ...string) (string, error) {
	fullArgs := append([]string{"diff"}, args...)
	cmd := exec.CommandContext(ctx, "git", fullArgs...) //nolint:gosec // args are from internal logic
	cmd.Dir = repoRoot
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr
	if err := cmd.Run(); err != nil {
		return "", fmt.Errorf("git diff %v: %w (stderr: %s)", args, err, stderr.String())
	}
	return stdout.String(), nil
}

// callClaudeForReview calls the claude CLI to perform the review.
// repoRoot is the repository root so the reviewer can access the full codebase.
func callClaudeForReview(repoRoot, prompt string) (string, error) {
	ctx, cancel := context.WithTimeout(context.Background(), wingmanReviewTimeout)
	defer cancel()

	cmd := exec.CommandContext(ctx, "claude",
		"--print",
		"--output-format", "json",
		"--model", wingmanReviewModel,
		"--setting-sources", "",
		// Grant read-only tool access so the reviewer can inspect source files
		// beyond just the diff. Permission bypass is safe here since tools are
		// restricted to read-only operations.
		"--allowedTools", "Read,Glob,Grep",
		"--permission-mode", "bypassPermissions",
	)

	// Run from repo root so the reviewer can read source files for context.
	// Loop-breaking is handled by --setting-sources "" (disables hooks) and
	// wingmanStripGitEnv (prevents git index pollution).
	cmd.Dir = repoRoot
	cmd.Env = wingmanStripGitEnv(os.Environ())

	cmd.Stdin = strings.NewReader(prompt)

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		var execErr *exec.Error
		if errors.As(err, &execErr) {
			return "", fmt.Errorf("claude CLI not found: %w", err)
		}
		var exitErr *exec.ExitError
		if errors.As(err, &exitErr) {
			return "", fmt.Errorf("claude CLI failed (exit %d): %s", exitErr.ExitCode(), stderr.String())
		}
		return "", fmt.Errorf("failed to run claude CLI: %w", err)
	}

	// Parse the CLI response
	var cliResponse wingmanCLIResponse
	if err := json.Unmarshal(stdout.Bytes(), &cliResponse); err != nil {
		return "", fmt.Errorf("failed to parse claude CLI response: %w", err)
	}

	return cliResponse.Result, nil
}

// readSessionContext reads the context.md file from the session's checkpoint
// metadata directory. Returns empty string if unavailable.
func readSessionContext(repoRoot, sessionID string) string {
	if sessionID == "" {
		return ""
	}
	contextPath := filepath.Join(repoRoot, ".entire", "metadata", sessionID, "context.md")
	data, err := os.ReadFile(contextPath) //nolint:gosec // path constructed from repoRoot + session ID
	if err != nil {
		if !errors.Is(err, os.ErrNotExist) {
			wingmanLog("WARNING: failed to read session context: %v", err)
		}
		return ""
	}
	return string(data)
}

// staleActiveSessionThreshold is the maximum age of a session state file in an
// ACTIVE phase before it is considered stale (crashed agent) and ignored by
// hasAnyLiveSession. Only applies to ACTIVE/ACTIVE_COMMITTED phases — an IDLE
// session is always considered live regardless of age (user may just be away).
const staleActiveSessionThreshold = 4 * time.Hour

// hasAnyLiveSession checks if any session is in a non-ENDED phase (IDLE,
// ACTIVE, or ACTIVE_COMMITTED). Used to decide whether to defer review
// application to the prompt-submit injection (visible to user) vs background
// auto-apply (invisible).
//
// ACTIVE/ACTIVE_COMMITTED sessions older than staleActiveSessionThreshold are
// skipped as likely orphaned from crashed processes. IDLE sessions are always
// considered live regardless of age.
func hasAnyLiveSession(repoRoot string) bool {
	sessDir := findSessionStateDir(repoRoot)
	if sessDir == "" {
		return false
	}

	entries, err := os.ReadDir(sessDir)
	if err != nil {
		return false
	}

	const maxCheck = 50
	checked := 0
	for _, entry := range entries {
		if checked >= maxCheck {
			wingmanLog("stopping live-session scan after %d entries; assuming live session may exist", checked)
			return true
		}
		name := entry.Name()
		if !strings.HasSuffix(name, ".json") {
			continue
		}
		checked++

		sid := strings.TrimSuffix(name, ".json")
		info := readSessionPhaseInfo(sessDir, sid)
		if info.Phase == "" || info.Phase == string(session.PhaseEnded) {
			continue
		}

		// ACTIVE/ACTIVE_COMMITTED sessions that haven't had a real agent
		// interaction in a long time are likely orphaned from crashed agents.
		// Uses LastInteractionTime from JSON (not file modtime) because
		// PostCommit saves all session files on every commit, refreshing
		// modtime even for stale sessions.
		// IDLE sessions are always considered live (user may just be away).
		if session.Phase(info.Phase).IsActive() {
			if info.LastInteractionTime != nil && time.Since(*info.LastInteractionTime) > staleActiveSessionThreshold {
				wingmanLog("skipping stale active session %s (phase=%s, last_interaction=%s ago)", sid, info.Phase, time.Since(*info.LastInteractionTime).Round(time.Second))
				continue
			}
		}

		wingmanLog("found live session %s (phase=%s)", sid, info.Phase)
		return true
	}

	return false
}

// findSessionStateDir locates the .git/entire-sessions/ directory by
// reading .git to handle both normal repos and worktrees.
func findSessionStateDir(repoRoot string) string {
	gitPath := filepath.Join(repoRoot, ".git")
	info, err := os.Stat(gitPath)
	if err != nil {
		return ""
	}

	var gitDir string
	if info.IsDir() {
		// Normal repo: .git is a directory
		gitDir = gitPath
	} else {
		// Worktree: .git is a file containing "gitdir: <path>"
		data, readErr := os.ReadFile(gitPath) //nolint:gosec // path from repoRoot
		if readErr != nil {
			return ""
		}
		content := strings.TrimSpace(string(data))
		if !strings.HasPrefix(content, "gitdir: ") {
			return ""
		}
		gitDir = strings.TrimPrefix(content, "gitdir: ")
		if !filepath.IsAbs(gitDir) {
			gitDir = filepath.Join(repoRoot, gitDir)
		}
		// For worktrees, session state is in the common dir
		// .git/worktrees/<name> → ../../ is the common .git dir
		commonDir := filepath.Join(gitDir, "..", "..")
		gitDir = filepath.Clean(commonDir)
	}

	sessDir := filepath.Join(gitDir, "entire-sessions")
	if _, statErr := os.Stat(sessDir); statErr != nil {
		return ""
	}
	return sessDir
}

// sessionPhaseInfo holds the subset of session state needed for liveness checks.
type sessionPhaseInfo struct {
	Phase               string
	LastInteractionTime *time.Time
}

func readSessionPhaseInfo(sessDir, sessionID string) sessionPhaseInfo {
	data, err := os.ReadFile(filepath.Join(sessDir, sessionID+".json")) //nolint:gosec // sessDir is from git internals
	if err != nil {
		return sessionPhaseInfo{}
	}
	var partial struct {
		Phase               string     `json:"phase"`
		LastInteractionTime *time.Time `json:"last_interaction_time,omitempty"`
	}
	if json.Unmarshal(data, &partial) != nil {
		return sessionPhaseInfo{}
	}
	return sessionPhaseInfo{
		Phase:               partial.Phase,
		LastInteractionTime: partial.LastInteractionTime,
	}
}

// runWingmanApply is the entrypoint for the __apply subcommand, spawned by the
// stop hook when a pending REVIEW.md is detected. It re-checks preconditions
// and triggers claude --continue to apply the review.
func runWingmanApply(repoRoot string) error {
	wingmanLog("apply process started (pid=%d)", os.Getpid())

	reviewPath := filepath.Join(repoRoot, wingmanReviewFile)
	if !fileExists(reviewPath) {
		wingmanLog("no REVIEW.md found at %s, nothing to apply", reviewPath)
		return nil
	}
	wingmanLog("REVIEW.md found at %s", reviewPath)

	// Retry prevention: check if apply was already attempted for this review
	state := loadWingmanStateDirect(repoRoot)
	switch {
	case state == nil:
		wingmanLog("no wingman state found, proceeding without session check")
	case state.ApplyAttemptedAt != nil:
		wingmanLog("apply already attempted at %s, skipping", state.ApplyAttemptedAt.Format(time.RFC3339))
		return nil
	default:
		wingmanLog("wingman state loaded: session=%s", state.SessionID)
	}

	// Re-check session hasn't become active (user may have typed during spawn delay).
	// IDLE and ENDED are safe — only ACTIVE/ACTIVE_COMMITTED should block.
	if state != nil && state.SessionID != "" {
		sessDir := findSessionStateDir(repoRoot)
		if sessDir != "" {
			phaseInfo := readSessionPhaseInfo(sessDir, state.SessionID)
			if phaseInfo.Phase != "" && session.Phase(phaseInfo.Phase).IsActive() {
				wingmanLog("session is active (phase=%s), aborting (next stop hook will retry)", phaseInfo.Phase)
				return nil
			}
			wingmanLog("session phase=%s, safe to proceed", phaseInfo.Phase)
		}
	}

	// Mark apply as attempted BEFORE triggering
	if state != nil {
		now := time.Now()
		state.ApplyAttemptedAt = &now
		saveWingmanStateDirect(repoRoot, state)
	}

	wingmanLog("triggering auto-apply via claude --continue")
	applyStart := time.Now()
	if err := triggerAutoApply(repoRoot); err != nil {
		wingmanLog("ERROR auto-apply failed after %s: %v", time.Since(applyStart).Round(time.Millisecond), err)
		return fmt.Errorf("failed to trigger auto-apply: %w", err)
	}
	wingmanLog("auto-apply completed in %s", time.Since(applyStart).Round(time.Millisecond))

	return nil
}

// triggerAutoApply spawns claude --continue to apply the review suggestions.
func triggerAutoApply(repoRoot string) error {
	ctx, cancel := context.WithTimeout(context.Background(), wingmanApplyTimeout)
	defer cancel()

	cmd := exec.CommandContext(ctx, "claude",
		"--continue",
		"--print",
		"--setting-sources", "",
		// Auto-accept edits so the agent can modify files and delete REVIEW.md
		// without requiring user consent (this runs in a background process).
		"--permission-mode", "acceptEdits",
		wingmanApplyInstruction,
	)
	cmd.Dir = repoRoot
	// Strip GIT_* env vars to prevent hook interference, and set
	// ENTIRE_WINGMAN_APPLY=1 so git hooks (post-commit) know not to
	// trigger another wingman review (prevents infinite recursion).
	env := wingmanStripGitEnv(os.Environ())
	env = append(env, "ENTIRE_WINGMAN_APPLY=1")
	cmd.Env = env

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	return cmd.Run() //nolint:wrapcheck // caller wraps
}

// wingmanStripGitEnv returns a copy of env with all GIT_* variables removed
// and the CLAUDECODE variable unset. GIT_* removal prevents a subprocess from
// discovering or modifying the parent's git repo. CLAUDECODE removal prevents
// the Claude CLI from refusing to start due to nested-session detection.
func wingmanStripGitEnv(env []string) []string {
	filtered := make([]string, 0, len(env))
	for _, e := range env {
		if strings.HasPrefix(e, "GIT_") || strings.HasPrefix(e, "CLAUDECODE=") {
			continue
		}
		filtered = append(filtered, e)
	}
	return filtered
}

// saveWingmanStateDirect writes the wingman state file directly to a known path
// under repoRoot, avoiding os.Chdir (which mutates process-wide state).
func saveWingmanStateDirect(repoRoot string, state *WingmanState) {
	statePath := filepath.Join(repoRoot, wingmanStateFile)
	if err := os.MkdirAll(filepath.Dir(statePath), 0o750); err != nil {
		return
	}
	data, err := json.MarshalIndent(state, "", "  ")
	if err != nil {
		return
	}
	//nolint:gosec,errcheck // G306: state file is config, not secrets; best-effort write
	_ = os.WriteFile(statePath, data, 0o644)
}

//go:build unix

package cli

import (
	"context"
	"fmt"
	"io"
	"os"
	"os/exec"
	"path/filepath"
	"syscall"
)

// spawnDetachedWingmanReview spawns a detached subprocess to run the wingman review.
// repoRoot is the repository root used to locate the log file.
// payloadPath is the path to the JSON payload file.
// On Unix, this uses process group detachment so the subprocess continues
// after the parent exits.
func spawnDetachedWingmanReview(repoRoot, payloadPath string) {
	executable, err := os.Executable()
	if err != nil {
		return
	}

	//nolint:gosec // G204: payloadPath is controlled internally, not user input
	cmd := exec.CommandContext(context.Background(), executable, "wingman", "__review", payloadPath)

	// Detach from parent process group so subprocess survives parent exit
	cmd.SysProcAttr = &syscall.SysProcAttr{
		Setpgid: true,
	}

	// Don't hold the working directory
	cmd.Dir = "/"

	// Inherit environment (needed for PATH, git config, etc.)
	cmd.Env = os.Environ()

	// Redirect stderr to a log file for debugging the background process.
	// This catches panics, errors, and all wingmanLog() output.
	cmd.Stdout = io.Discard
	var logFile *os.File
	logDir := filepath.Join(repoRoot, ".entire", "logs")
	if mkErr := os.MkdirAll(logDir, 0o750); mkErr == nil {
		//nolint:gosec // G304: path is constructed from repoRoot + constants
		if f, openErr := os.OpenFile(filepath.Join(logDir, "wingman.log"),
			os.O_CREATE|os.O_APPEND|os.O_WRONLY, 0o600); openErr == nil {
			logFile = f
			cmd.Stderr = f
		} else {
			cmd.Stderr = io.Discard
		}
	} else {
		cmd.Stderr = io.Discard
	}

	// Start the process (non-blocking)
	if err := cmd.Start(); err != nil {
		fmt.Fprintf(os.Stderr, "[wingman] Failed to spawn review subprocess: %v\n", err)
		if logFile != nil {
			_ = logFile.Close()
		}
		return
	}

	pid := cmd.Process.Pid
	fmt.Fprintf(os.Stderr, "[wingman] Review subprocess spawned (pid=%d)\n", pid)

	// Close the parent's copy of the log file descriptor. The child process
	// received its own copy via dup during Start(), so this won't affect it.
	if logFile != nil {
		_ = logFile.Close()
	}

	// Release the process so it can run independently
	//nolint:errcheck // Best effort - process should continue regardless
	_ = cmd.Process.Release()
}

// spawnDetachedWingmanApply spawns a detached subprocess to auto-apply the
// pending REVIEW.md via claude --continue. Called from the stop hook when a
// review is pending after the agent turn ends.
func spawnDetachedWingmanApply(repoRoot string) {
	executable, err := os.Executable()
	if err != nil {
		return
	}

	//nolint:gosec // G204: repoRoot is from paths.RepoRoot(), not user input
	cmd := exec.CommandContext(context.Background(), executable, "wingman", "__apply", repoRoot)

	cmd.SysProcAttr = &syscall.SysProcAttr{
		Setpgid: true,
	}

	cmd.Dir = "/"
	cmd.Env = os.Environ()

	cmd.Stdout = io.Discard
	var applyLogFile *os.File
	logDir := filepath.Join(repoRoot, ".entire", "logs")
	if mkErr := os.MkdirAll(logDir, 0o750); mkErr == nil {
		//nolint:gosec // G304: path is constructed from repoRoot + constants
		if f, openErr := os.OpenFile(filepath.Join(logDir, "wingman.log"),
			os.O_CREATE|os.O_APPEND|os.O_WRONLY, 0o600); openErr == nil {
			applyLogFile = f
			cmd.Stderr = f
		} else {
			cmd.Stderr = io.Discard
		}
	} else {
		cmd.Stderr = io.Discard
	}

	if err := cmd.Start(); err != nil {
		fmt.Fprintf(os.Stderr, "[wingman] Failed to spawn apply subprocess: %v\n", err)
		if applyLogFile != nil {
			_ = applyLogFile.Close()
		}
		return
	}

	pid := cmd.Process.Pid
	fmt.Fprintf(os.Stderr, "[wingman] Apply subprocess spawned (pid=%d)\n", pid)

	// Close the parent's copy of the log file descriptor. The child process
	// received its own copy via dup during Start(), so this won't affect it.
	if applyLogFile != nil {
		_ = applyLogFile.Close()
	}

	//nolint:errcheck // Best effort - process should continue regardless
	_ = cmd.Process.Release()
}

